={{ (() => {
  const r1 = $('RED: CMO Attack').first().json;
  const r2 = $('RED: CFO Attack').first().json;
  const parse = (r) => {
    const txt = r.content.filter(b => b.type === 'text').map(b => b.text).join('\n');
    try { return JSON.parse(txt); } catch(e) {
      const m = txt.match(/\{[\s\S]*\}/);
      return m ? JSON.parse(m[0]) : { agent: '?', vulnerabilities: [] };
    }
  };
  const a1 = parse(r1);
  const a2 = parse(r2);
  const formatBlock = (attacks) => {
    return attacks.map(atk => 
      atk.vulnerabilities.map(v => 
        `[${v.id}] (${v.severity}) ${v.title} — from ${atk.agent}\n  Description: ${v.description}\n  Failure scenario: ${v.failure_scenario}`
      ).join('\n\n')
    ).join('\n\n');
  };
  return {
    attacks: [a1, a2],
    attacks_block: formatBlock([a1, a2])
  };
})() }}

