    parsed = m ? JSON.parse(m[0]) : { adjudications: [] };
  }
  const adjs = parsed.adjudications || [];
  const formatBlock = adjs.map(a => 
    `[${a.vulnerability_id}] ${a.vulnerability_title} (severity: ${a.severity})\n  Verdict: ${a.verdict}\n  Reasoning: ${a.reasoning}\n  Defense gaps: ${a.defense_gaps}\n  Recommended action: ${a.recommended_action}`
  ).join('\n\n');
  return {
    adjudications: adjs,
    adjudication_block: formatBlock
  };
})() }}

